import { z } from 'zod';

// ── Pagination ──────────────────────────────────────────────────────────────

export const paginationQuerySchema = z.object({
	page: z.coerce.number().int().positive().default(1),
	perPage: z.coerce.number().int().positive().max(100).default(20)
});
export type PaginationQuery = z.infer<typeof paginationQuerySchema>;

export const paginatedResponseSchema = <T extends z.ZodTypeAny>(itemSchema: T) =>
	z.object({
		data: z.array(itemSchema),
		pagination: z.object({
			page: z.number().int().positive(),
			perPage: z.number().int().positive(),
			total: z.number().int().nonnegative(),
			totalPages: z.number().int().positive()
		})
	});

// ── Error response ──────────────────────────────────────────────────────────

export const fieldErrorSchema = z.object({
	field: z.string(),
	message: z.string()
});
export type FieldError = z.infer<typeof fieldErrorSchema>;

export const errorResponseSchema = z.object({
	error: z.object({
		code: z.string(),
		message: z.string(),
		details: z.array(fieldErrorSchema).optional()
	})
});
export type ErrorResponse = z.infer<typeof errorResponseSchema>;

// ── ID formats ──────────────────────────────────────────────────────────────

export const milestoneIdSchema = z.string().regex(/^MS-\d+$/, 'Must match MS-{seq}');
export const moduleIdSchema = z.string().regex(/^MOD-\d+-\d+$/, 'Must match MOD-{ms_seq}-{seq}');
export const taskIdSchema = z.string().regex(/^TASK-\d+$/, 'Must match TASK-{seq}');

// ── Source markdown size limit (1 MB) ───────────────────────────────────────

export const SOURCE_MD_MAX_BYTES = 1_048_576;
export const sourceMdSchema = z
	.string()
	.max(SOURCE_MD_MAX_BYTES, `source_md must be under ${SOURCE_MD_MAX_BYTES} bytes`);

import { z } from 'zod';
import { milestoneStatusEnum } from '../db/schema.js';
import { sourceMdSchema, milestoneIdSchema } from './common.js';

// ── Create ──────────────────────────────────────────────────────────────────

export const createMilestoneSchema = z.object({
	title: z.string().min(1, 'Title is required').max(200, 'Title must be under 200 characters'),
	sourceMd: sourceMdSchema.optional(),
	gitUrl: z.string().url('Invalid URL').optional().or(z.literal(''))
});
export type CreateMilestoneInput = z.infer<typeof createMilestoneSchema>;

// ── Update ──────────────────────────────────────────────────────────────────

export const updateMilestoneSchema = z.object({
	title: z.string().min(1).max(200).optional(),
	sourceMd: sourceMdSchema.optional(),
	gitUrl: z.string().url().optional().or(z.literal('')),
	status: z.enum(milestoneStatusEnum).optional()
});
export type UpdateMilestoneInput = z.infer<typeof updateMilestoneSchema>;

// ── Response ────────────────────────────────────────────────────────────────

export const milestoneResponseSchema = z.object({
	id: milestoneIdSchema,
	title: z.string(),
	sourceMd: z.string().nullable(),
	gitUrl: z.string().nullable(),
	status: z.enum(milestoneStatusEnum),
	createdAt: z.string().datetime() // ISO 8601
});
export type MilestoneResponse = z.infer<typeof milestoneResponseSchema>;

import { z } from 'zod';
import { moduleStatusEnum } from '../db/schema.js';
import { moduleIdSchema, milestoneIdSchema } from './common.js';

// ── Create ──────────────────────────────────────────────────────────────────

export const createModuleSchema = z.object({
	milestoneId: milestoneIdSchema,
	name: z.string().min(1, 'Name is required').max(200, 'Name must be under 200 characters'),
	description: z.string().max(5000).optional(),
	sortOrder: z.number().int().nonnegative().default(0)
});
export type CreateModuleInput = z.infer<typeof createModuleSchema>;

// ── Update ──────────────────────────────────────────────────────────────────

export const updateModuleSchema = z.object({
	name: z.string().min(1).max(200).optional(),
	description: z.string().max(5000).optional(),
	status: z.enum(moduleStatusEnum).optional(),
	sortOrder: z.number().int().nonnegative().optional()
});
export type UpdateModuleInput = z.infer<typeof updateModuleSchema>;

// ── Response ────────────────────────────────────────────────────────────────

export const moduleResponseSchema = z.object({
	id: moduleIdSchema,
	milestoneId: milestoneIdSchema,
	name: z.string(),
	description: z.string().nullable(),
	status: z.enum(moduleStatusEnum),
	sortOrder: z.number().int()
});
export type ModuleResponse = z.infer<typeof moduleResponseSchema>;

import { z } from 'zod';
import { taskStatusEnum } from '../db/schema.js';
import { taskIdSchema, moduleIdSchema } from './common.js';

// ── Status transition map ───────────────────────────────────────────────────

const validTransitions: Record<string, string[]> = {
	todo: ['in-progress', 'skipped'],
	'in-progress': ['blocked', 'review', 'todo'],
	blocked: ['in-progress', 'todo'],
	review: ['done', 'in-progress'],
	done: [],
	skipped: []
};

export function isValidTransition(from: string, to: string): boolean {
	return validTransitions[from]?.includes(to) ?? false;
}

// ── Claim ───────────────────────────────────────────────────────────────────

export const claimTaskSchema = z.object({
	assignee: z.string().min(1, 'Assignee is required').max(100)
});
export type ClaimTaskInput = z.infer<typeof claimTaskSchema>;

// ── Progress update ─────────────────────────────────────────────────────────

export const progressTaskSchema = z.object({
	progressMessage: z.string().max(5000).optional(),
	subTotal: z.number().int().nonnegative().optional(),
	subDone: z.number().int().nonnegative().optional()
}).refine(
	(data) => {
		if (data.subTotal !== undefined && data.subDone !== undefined) {
			return data.subDone <= data.subTotal;
		}
		return true;
	},
	{ message: 'sub_done cannot exceed sub_total', path: ['subDone'] }
);
export type ProgressTaskInput = z.infer<typeof progressTaskSchema>;

